import{_ as e,o as s,c as i,ag as t}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"如何添加配置文件","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qa/add-config.md","filePath":"zh/qa/add-config.md","lastUpdated":1782688753000}'),o={name:"zh/qa/add-config.md"};function n(p,a,l,c,d,r){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="如何添加配置文件" tabindex="-1">如何添加配置文件 <a class="header-anchor" href="#如何添加配置文件" aria-label="Permalink to &quot;如何添加配置文件&quot;">​</a></h1><p>EasyYapi 支持多种方式向项目添加配置文件。</p><h2 id="方式一-项目根目录配置" tabindex="-1">方式一：项目根目录配置 <a class="header-anchor" href="#方式一-项目根目录配置" aria-label="Permalink to &quot;方式一：项目根目录配置&quot;">​</a></h2><p>在项目根目录（你在 IDE 中打开的文件夹）创建 <code>.easy.api.config</code> 文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>your-project/</span></span>
<span class="line"><span>├── .easy.api.config</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>└── pom.xml</span></span></code></pre></div><blockquote><p><strong>多模块工程注意：</strong> 不存在按模块划分的配置层。规则文件仅基于工程根目录 解析，发现过程不会向下递归到子目录。若你将父目录作为工程打开，放在 <code>module-a/</code> 等子目录中的配置文件不会被加载。若希望某个模块拥有独立规则， 请将该模块文件夹单独作为工程打开。</p></blockquote><h2 id="方式二-远程配置" tabindex="-1">方式二：远程配置 <a class="header-anchor" href="#方式二-远程配置" aria-label="Permalink to &quot;方式二：远程配置&quot;">​</a></h2><p>在本地配置文件中配置远程 URL：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">remote.url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=http://your-config-server.com/easy-api.config</span></span></code></pre></div><h2 id="配置优先级" tabindex="-1">配置优先级 <a class="header-anchor" href="#配置优先级" aria-label="Permalink to &quot;配置优先级&quot;">​</a></h2><ol><li>工程规则（<code>.easyapi/</code> / 项目根目录下的 <code>.easy.api.config*</code>）—— 最高优先级</li><li>扩展规则（内置框架预设）</li><li>远程配置</li><li>全局规则（<code>~/.easyapi/</code>）—— 最低优先级</li></ol><p>详见 <a href="/zh/settings/local-file-config">本地配置文件</a> 和 <a href="/zh/settings/remote-config">远程配置文件</a>。</p>`,12)])])}const u=e(o,[["render",n]]);export{g as __pageData,u as default};
